sql:
SELECT AVG(od.bmi) AS average_bmi
FROM mortality_data md
INNER JOIN obesity_data od ON md.patient_id = od.patient_id;

SELECT COUNT(*) 
FROM covid_status
WHERE status_name = 'Recovered';

SELECT bmi, waist_circumference, body_fat_percentage 
FROM obesity_data 
WHERE bmi > 30;

SELECT patient_id 
FROM hypertension_data 
WHERE treatment_plan = 'Medication';

SELECT DISTINCT patient_id
FROM obesity_data
WHERE bmi > 30;

SELECT COUNT(patient_id)
FROM mortality_data
WHERE TIME(date_of_death) BETWEEN '08:00:00' AND '16:00:00';

SELECT comorbidity_name, severity_level
FROM comorbidities
WHERE severity_level = 'Severe';

SELECT users.user_name, users.email
FROM users
INNER JOIN role_permissions ON users.role = role_permissions.role_name;
